{"code": "import sys

def mapRow(this_row, header_dict, precursors_mapping, sequences_mapping, protein_mapping):
    # Extract and strip whitespace from peptide name
    peptide_name = this_row[header_dict['FullPeptideName']].strip()

    # Split fragment annotations on ';' and remove empty trailing entries
    fragment_ann = this_row[header_dict['aggr_Fragment_Annotation']]
    transitions = [t for t in fragment_ann.split(';') if t]

    # Split precursor annotations on ';' and remove empty trailing entries
    prec_ann = this_row[header_dict['aggr_prec_Fragment_Annotation']]
    pr_transitions = [t for t in prec_ann.split(';') if t]

    # If no transitions are present, return immediately
    if not transitions:
        return

    # Remove duplicates from transitions while preserving order
    seen = set()
    transitions_dedup = []
    for t in transitions:
        if t not in seen:
            seen.add(t)
            transitions_dedup.append(t)
    transitions = transitions_dedup

    # Remove duplicates from pr_transitions while preserving order
    seen = set()
    pr_transitions_dedup = []
    for t in pr_transitions:
        if t not in seen:
            seen.add(t)
            pr_transitions_dedup.append(t)
    pr_transitions = pr_transitions_dedup

    # Read charge state, strip whitespace, default to '0' if 'NA' or empty
    charge = this_row[header_dict['Charge']].strip()
    if charge == 'NA' or charge == '':
        charge = '0'

    # Build keys
    key1 = f"{peptide_name}/{charge}"
    key2 = f"{peptide_name}/{charge}_pr"

    # Map keys to transitions in precursors_mapping
    precursors_mapping[key1] = transitions
    precursors_mapping[key2] = pr_transitions

    # In sequences_mapping, append both keys to the list for peptide_name
    if peptide_name not in sequences_mapping:
        sequences_mapping[peptide_name] = []
    sequences_mapping[peptide_name].append(key1)
    sequences_mapping[peptide_name].append(key2)

    # In protein_mapping, append peptide_name to the list for corresponding protein (avoid duplicates)
    protein_name = this_row[header_dict['ProteinName']]
    if protein_name not in protein_mapping:
        protein_mapping[protein_name] = []
    if peptide_name not in protein_mapping[protein_name]:
        protein_mapping[protein_name].append(peptide_name)


def main():
    # Test 1: Basic row
    header = ['FullPeptideName', 'aggr_Fragment_Annotation', 'aggr_prec_Fragment_Annotation', 'Charge', 'ProteinName']
    row = ['PEPTIDESEQ', 'b1;b2;b3;', 'p1;p2;', '2', 'P12345']
    header_dict = {name: idx for idx, name in enumerate(header)}
    precursors_mapping = {}
    sequences_mapping = {}
    protein_mapping = {}
    mapRow(row, header_dict, precursors_mapping, sequences_mapping, protein_mapping)
    assert precursors_mapping == {'PEPTIDESEQ/2': ['b1', 'b2', 'b3'], 'PEPTIDESEQ/2_pr': ['p1', 'p2']}
    assert sequences_mapping == {'PEPTIDESEQ': ['PEPTIDESEQ/2', 'PEPTIDESEQ/2_pr']}
    assert protein_mapping == {'P12345': ['PEPTIDESEQ']}
    print("Test 1 passed: Basic row")

    # Test 2: Empty fragment annotations (early return)
    row2 = ['PEPTIDE', '', 'p1;p2;', '2', 'P54321']
    precursors_mapping = {}
    sequences_mapping = {}
    protein_mapping = {}
    mapRow(row2, header_dict, precursors_mapping, sequences_mapping, protein_mapping)
    assert precursors_mapping == {}
    assert sequences_mapping == {}
    assert protein_mapping == {}
    print("Test 2 passed: Empty fragment annotations -> early return")

    # Test 3: Charge is 'NA' -> default to '0'
    row3 = ['PEPTIDE3', 'b1;b2;', 'p1;', 'NA', 'P99999']
    precursors_mapping = {}
    sequences_mapping = {}
    protein_mapping = {}
    mapRow(row3, header_dict, precursors_mapping, sequences_mapping, protein_mapping)
    assert 'PEPTIDE3/0' in precursors_mapping
    assert 'PEPTIDE3/0_pr' in precursors_mapping
    print("Test 3 passed: Charge 'NA' defaults to '0'")

    # Test 4: Charge is empty -> default to '0'
    row4 = ['PEPTIDE4', 'b1;b2;', 'p1;', '', 'P88888']
    precursors_mapping = {}
    sequences_mapping = {}
    protein_mapping = {}
    mapRow(row4, header_dict, precursors_mapping, sequences_mapping, protein_mapping)
    assert 'PEPTIDE4/0' in precursors_mapping
    print("Test 4 passed: Empty charge defaults to '0'")

    # Test 5: Whitespace stripping
    row5 = ['  PEPTIDE5  ', 'b1;b2;', 'p1;', ' 3 ', 'P77777']
    precursors_mapping = {}
    sequences_mapping = {}
    protein_mapping = {}
    mapRow(row5, header_dict, precursors_mapping, sequences_mapping, protein_mapping)
    assert 'PEPTIDE5/3' in precursors_mapping
    assert 'PEPTIDE5/3_pr' in precursors_mapping
    assert sequences_mapping == {'PEPTIDE5': ['PEPTIDE5/3', 'PEPTIDE5/3_pr']}
    print("Test 5 passed: Whitespace stripping")

    # Test 6: Deduplication of transitions
    row6 = ['PEPTIDE6', 'b1;b2;b1;b3;b2;', 'p1;p2;p1;', '1', 'P66666']
    precursors_mapping = {}
    sequences_mapping = {}
    protein_mapping = {}
    mapRow(row6, header_dict, precursors_mapping, sequences_mapping, protein_mapping)
    assert precursors_mapping['PEPTIDE6/1'] == ['b1', 'b2', 'b3'], f"Got {precursors_mapping['PEPTIDE6/1']}"
    assert precursors_mapping['PEPTIDE6/1_pr'] == ['p1', 'p2'], f"Got {precursors_mapping['PEPTIDE6/1_pr']}"
    print("Test 6 passed: Deduplication of transitions")

    # Test 7: No trailing empty entries
    row7 = ['PEPTIDE7', 'b1;b2;b3', 'p1;p2', '1', 'P55555']
    precursors_mapping = {}
    sequences_mapping = {}
    protein_mapping = {}
    mapRow(row7, header_dict, precursors_mapping, sequences_mapping, protein_mapping)
    assert precursors_mapping['PEPTIDE7/1'] == ['b1', 'b2', 'b3']
    assert precursors_mapping['PEPTIDE7/1_pr'] == ['p1', 'p2']
    print("Test 7 passed: No trailing empty (already no trailing semicolon)")

    # Test 8: Protein mapping avoids duplicates
    row8a = ['PEPTIDE8', 'b1;', 'p1;', '1', 'P44444']
    row8b = ['PEPTIDE8', 'b2;', 'p2;', '1', 'P44444']  # same protein, same peptide
    precursors_mapping = {}
    sequences_mapping = {}
    protein_mapping = {}
    mapRow(row8a, header_dict, precursors_mapping, sequences_mapping, protein_mapping)
    mapRow(row8b, header_dict, precursors_mapping, sequences_mapping, protein_mapping)
    # Peptide should appear only once in protein mapping
    assert len(protein_mapping['P44444']) == 1
    print("Test 8 passed: Protein mapping avoids duplicates")

    print("\nAll tests passed!")

if __name__ == '__main__':
